import{c as r,Q as o,j as i,g as e,n as l}from"./chunks/framework.hhGiamYR.js";const _=JSON.parse('{"title":"论德意志事务及其皇帝","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/199-论德意志事务及其皇帝.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/199-论德意志事务及其皇帝.md"}'),t={name:"research/machiavelli/machiavelli/diplomatic/lower/199-论德意志事务及其皇帝.md"};function s(n,a,c,m,d,p){return o(),i("div",null,[...a[0]||(a[0]=[e("h1",{id:"论德意志事务及其皇帝",tabindex:"-1"},[l("论德意志事务及其皇帝 "),e("a",{class:"header-anchor",href:"#论德意志事务及其皇帝","aria-label":'Permalink to "论德意志事务及其皇帝"'},"​")],-1),e("p",null,"论德意志事务及其皇帝",-1),e("p",null,"Discorso sopra le cose della Magna e sopra 1' imperatore; 曾用标题Discorso di N.M.sopra le cose d’A lemagna e sopral' imperatore; 创作于1509年8-9月。",-1),e("p",null,"当我去年(1508年)自德意志返回时，我曾写过一些关于德意志皇帝的 事情。我不知道还有什么可补充的；所以我将只谈谈他的性格。无论当今还 是过去都没有人比皇帝更加挥霍无度了。正因为如此，不管他的处境和命 运如何，他总是手头紧张，钱永远不够花。他是个非常容易改变想法的 人：今天想要的东西，第二天就弃之不顾。他不向任何人征求意见，却又 轻信每一个人。他想要拥有一切他无法拥有的东西，对他能够拥有的东西 则不屑一顾。因此，他总是做出自相矛盾的决定。但他也是个在军事方面 非常精明能干的人：他领军有方，并以正义和纪律来治军；他克服疲劳的 能力不亚于任何人，在面对危险时勇敢无畏；所以，作为军事统帅，他不 逊于任何人。他在接见人时和蔼可亲，但前提是被接见者必须对他的胃 口；他不喜欢大使们前来觐见，除非是他本人把他们叫来的。他是个口风 很紧的人。他的身体和精神总是处于持续的躁动之中，经常朝令夕改。 这就使得出使到他身边的任务极为困难，因为一位特使不管是由君主还是 由共和国派出的，他最重要的任务都是去预测谈判和事件的未来走向。毕",-1),e("p",null,"*初稿由曹钦根据英译文(“Discourse on the Affairs of Germany and on the Emperor”,in The Historical, Political,and Diplomatic Writings of Niccolo Machiavelli,tr.from the Italian by Christian E.Detmold,Vol.4, Boston:J.R.Osgood and Company,1882;“Discourse on the Affairs of Germany and Its Emperor”,in The Essential Writings of Machiavelli, translated by Peter Constantine,New York: Moderm Library,2007)译出，文 字经刘训练校订。",-1),e("p",null,"竞，如果一位特使能够明智地进行预测，并把这些预测很好地传达给他 的政府，他就能让他的政府占尽先机，在合适的时间采取行动。当一位特 使正确做出预测时，就能给自己带来荣誉，为他的政府带来好处；而如果 他做出了糟糕的预测，情形就完全相反了。为了更好地理解这一点，假想 你现在需要在发动战争与进行和谈之间进行抉择。若想出色地履行自己的 职责，你就需要说明，盛行的意见是倾向于战争还是和谈。战争必须通过 军队实力、金钱、管理水平和命运来加以考量，在这些方面占据上风的一 方更有可能获得胜利。在对谁更有可能获胜的问题进行评估之后，大使必 须能够让自己的评估在本国得到理解，从而使他和他的国家可以更好地决 策。谈判将在各方之间展开：威尼斯人和皇帝的谈判、皇帝和法国的谈 判、皇帝和教皇的谈判，以及皇帝和你们的谈判。在涉及你们的谈判中， 你们应该不难做出正确的预测，并判断皇帝的意图——他到底想要什么、 他的想法转向哪里，以及什么会让他挺进或退缩。 一旦你们搞明白了这一 点，就必须做出判断：是敷衍拖延更为有利，还是当机立断更为有利。在 职权范围之内，这些决策就要由你们来做了。 \u2028论德意志事务及其皇帝",-1)])])}const f=r(t,[["render",s]]);export{_ as __pageData,f as default};
